import { NavLink } from "react-router-dom";
import "./Sidebar.css";

function Sidebar() {
  return (
    <div className="sidebar">
      <h2 className="logo">Employee MS</h2>

      <NavLink to="/dashboard" end>Dashboard</NavLink>
      <NavLink to="/dashboard/employee-details">Employees</NavLink>
      <NavLink to="/dashboard/calendar">Calendar</NavLink>
      <NavLink to="/dashboard/timesheet">Timesheet</NavLink>
    </div>
  );
}

export default Sidebar;
